package com.aadil.jobtracker.responses;public class APIResponse <DataType>{    private boolean success;    private DataType data;    private String message;    public boolean isSuccess() {        return success;    }    public DataType getData() {        return data;    }    public String getMessage() {        return message;    }    public APIResponse(boolean success, DataType data, String message) {        this.success = success;        this.data = data;        this.message = message;    }}